Here's a basic code for a Discord.js v14 bot that has one command, "ban". All commands are slash commands.

```javascript
const { Client, Intents } = require('discord.js');

const client = new Client({ intents: [Intents.FLAGS.GUILDS] });

client.once('ready', () => {
  console.log('Ready!');

  client.user.setPresence({ status: 'online', activity: { type: 'PLAYING', name: 'help' } });
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const { command } = interaction;

  if (command === 'ban') {
    const member = interaction.member;
    if (!member) return;

    try {
      await member.kick();
      await interaction.reply('Banned **' + member.username + '**!');
    } catch (err) {
      console.error(err);
    }
  }
});

client.login('YOUR_DISCORD_BOT_TOKEN');
```

