Here's an example C++ function that converts Markdown to HTML using the `pandoc` library:

```cpp
#include <string>
#include <sstream>
#include <iostream>
#include <fstream>
#include <sstream>
#include <sstream>
#include <pandoc.h>

using namespace std;

string MarkdownToHTML(const string& markdown) {
  std::stringstream ss;
  std::ostream& out = ss << endl;

  pdflatex::Document doc;
  doc.set_output_file("out.html");

  doc << markdown;

  return ss.str();
}
```

