Here's an example of a function that takes an array of 5 numbers and checks if any of them is a valid prime number. If it finds a prime number, it logs the number to the console:
```
const arr = [4, 8, 10, 12, 16];

function checkPrimes(arr) {
  for (let num of arr) {
    if (isPrime(num)) {
      console.log(num);
    }
  }
}

function isPrime(num) {
  // Check if the number is negative or zero
  if (num <= 1) return false;

  // Check if the number is even
  if (num % 2 === 0) return false;

  // Iterate over all the numbers up to the square root of the number
  for (let i = 3; i * i <= num; i += 2) {
    if (num % i === 0) return false;
  }

  return true;
}
```

Calling the `checkPrimes()` function with the `arr` variable as an argument will log all the prime numbers in the array to the console.

